    void to_json(nlohmann::json &j, const Sensor &v) { j = sensorToJson(v); }

    void to_json(nlohmann::json &j, const AdjustPosition &v)
    {
      j["type"] = v.type;
      opt_to_json(j, "once", v.once);
      opt_to_json(j, "enabled", v.enabled);
      if (v.sensor != nullptr)
        j["sensor"] = sensorToJson(*v.sensor);
      j["offset"] = v.offset;
    }

