    nlohmann::json actionToJson(const Action &a)
    {
      nlohmann::json j;
      j["type"] = a.type;
      switch (a.type)
      {
      case Type::AddToHostileTargetMemory:
        j = static_cast<const AddToHostileTargetMemory &>(a);
        break;
      case Type::Appearance:
        j = static_cast<const Appearance &>(a);
        break;
      case Type::ApplyEntityEffect:
        j = static_cast<const ApplyEntityEffect &>(a);
        break;
      case Type::CombatAbility:
        j = static_cast<const CombatAbility &>(a);
        break;
      case Type::CompleteTask:
        j = static_cast<const CompleteTask &>(a);
        break;
      case Type::Crouch:
        j = static_cast<const Crouch &>(a);
        break;
      case Type::DelayDespawn:
        j = static_cast<const DelayDespawn &>(a);
        break;
      case Type::Despawn:
        j = static_cast<const Despawn &>(a);
        break;
      case Type::Die:
        j = static_cast<const Die &>(a);
        break;
      case Type::DisplayName:
        j = static_cast<const DisplayName &>(a);
        break;
      case Type::DropItem:
        j = static_cast<const DropItem &>(a);
        break;
      case Type::FlockState:
        j = static_cast<const FlockState &>(a);
        break;
      case Type::FlockTarget:
        j = static_cast<const FlockTarget &>(a);
        break;
      case Type::IgnoreForAvoidance:
        j = static_cast<const IgnoreForAvoidance &>(a);
        break;
      case Type::Inventory:
        j = static_cast<const Inventory &>(a);
        break;
      case Type::JoinFlock:
        j = static_cast<const JoinFlock &>(a);
        break;
      case Type::LeaveFlock:
        j = static_cast<const LeaveFlock &>(a);
        break;
      case Type::LockOnInteractionTarget:
        j = static_cast<const LockOnInteractionTarget &>(a);
        break;
      case Type::Log:
        j = static_cast<const Log &>(a);
        break;
      case Type::ModelAttachment:
        j = static_cast<const ModelAttachment &>(a);
        break;
      case Type::Mount:
        j = static_cast<const Mount &>(a);
        break;
      case Type::Nothing:
        j = static_cast<const Nothing &>(a);
        break;
      case Type::Notify:
        j = static_cast<const Notify &>(a);
        break;
      case Type::OpenBarterShop:
        j = static_cast<const OpenBarterShop &>(a);
        break;
      case Type::OpenShop:
        j = static_cast<const OpenShop &>(a);
        break;
      case Type::OverrideAltitude:
        j = static_cast<const OverrideAltitude &>(a);
        break;
      case Type::OverrideAttitude:
        j = static_cast<const OverrideAttitude &>(a);
        break;
      case Type::ParentState:
        j = static_cast<const ParentState &>(a);
        break;
      case Type::PickUpItem:
        j = static_cast<const PickUpItem &>(a);
        break;
      case Type::PlaceBlock:
        j = static_cast<const PlaceBlock &>(a);
        break;
      case Type::PlaySound:
        j = static_cast<const PlaySound &>(a);
        break;
      case Type::Random:
        j = static_cast<const Random &>(a);
        break;
      case Type::RecomputePath:
        j = static_cast<const RecomputePath &>(a);
        break;
      case Type::ReleaseTarget:
        j = static_cast<const ReleaseTarget &>(a);
        break;
      case Type::Remove:
        j = static_cast<const Remove &>(a);
        break;
      case Type::ResetBlockSensors:
        j = static_cast<const ResetBlockSensors &>(a);
        break;
      case Type::ResetInstructions:
        j = static_cast<const ResetInstructions &>(a);
        break;
      case Type::ResetPath:
        j = static_cast<const ResetPath &>(a);
        break;
      case Type::ResetSearchRays:
        j = static_cast<const ResetSearchRays &>(a);
        break;
      case Type::Role:
        j = static_cast<const Role &>(a);
        break;
      case Type::Sequence:
        j = static_cast<const Sequence &>(a);
        break;
      case Type::SetAlarm:
        j = static_cast<const SetAlarm &>(a);
        break;
      case Type::SetBlockToPlace:
        j = static_cast<const SetBlockToPlace &>(a);
        break;
      case Type::SetFlag:
        j = static_cast<const SetFlag &>(a);
        break;
      case Type::SetInteractable:
        j = static_cast<const SetInteractable &>(a);
        break;
      case Type::SetLeashPosition:
        j = static_cast<const SetLeashPosition &>(a);
        break;
      case Type::SetMarkedTarget:
        j = static_cast<const SetMarkedTarget &>(a);
        break;
      case Type::SetStat:
        j = static_cast<const SetStat &>(a);
        break;
      case Type::StartObjective:
        j = static_cast<const StartObjective &>(a);
        break;
      case Type::State:
        j = static_cast<const State &>(a);
        break;
      case Type::StorePosition:
        j = static_cast<const StorePosition &>(a);
        break;
      case Type::Timeout:
        j = static_cast<const Timeout &>(a);
        break;
      case Type::TimerContinue:
        j = static_cast<const TimerContinue &>(a);
        break;
      case Type::TimerModify:
        j = static_cast<const TimerModify &>(a);
        break;
      case Type::TimerPause:
        j = static_cast<const TimerPause &>(a);
        break;
      case Type::TimerRestart:
        j = static_cast<const TimerRestart &>(a);
        break;
      case Type::TimerStart:
        j = static_cast<const TimerStart &>(a);
        break;
      case Type::TimerStop:
        j = static_cast<const TimerStop &>(a);
        break;
      case Type::ToggleStateEvaluator:
        j = static_cast<const ToggleStateEvaluator &>(a);
        break;
      case Type::TriggerSpawnBeacon:
        j = static_cast<const TriggerSpawnBeacon &>(a);
        break;
      case Type::TriggerSpawners:
        j = static_cast<const TriggerSpawners &>(a);
        break;
      }
      return j;
    }

    void to_json(nlohmann::json &j, const Action &v) { j = actionToJson(v); }

    void to_json(nlohmann::json &j, const WeightedAction &v)
    {
      if (v.action != nullptr)
        j["action"] = actionToJson(*v.action);
      j["weight"] = v.weight;
    }

    void to_json(nlohmann::json &j, const ActionList &v)
    {
      nlohmann::json arr = nlohmann::json::array();
      for (const auto &a : v.actions)
      {
        if (a == nullptr)
          continue;

        arr.push_back(actionToJson(*a));
      }
      j["actions"] = arr;
    }

