  void to_json(nlohmann::json &j, const Instruction &v)
  {
    j["name"] = v.name;
    opt_to_json(j, "comment", v.comment);
    opt_to_json(j, "enabled", v.enabled);

    if (v.sensor != nullptr)
      j["sensor"] = Sensor::sensorToJson(*v.sensor);
    if (v.bodyMotion.has_value())
      j["bodyMotion"] = v.bodyMotion.value();
    if (v.headMotion.has_value())
      j["headMotion"] = v.headMotion.value();

    nlohmann::json actArr = nlohmann::json::array();
    for (const auto &a : v.actions)
      actArr.push_back(Action::actionToJson(*a));
    if (!actArr.empty())
      j["actions"] = actArr;

    opt_to_json(j, "actionsBlocking", v.actionsBlocking);
    opt_to_json(j, "actionsAtomic", v.actionsAtomic);

    if (!v.instructions.empty())
      j["instructions"] = v.instructions;

    opt_to_json(j, "continue", v.cont);
    opt_to_json(j, "weight", v.weight);
  }

  void to_json(nlohmann::json &j, const StateTransition &v)
  {
    j["priority"] = v.priority;
    j["from"] = v.from;
    j["to"] = v.to;
    opt_to_json(j, "enabled", v.enabled);
  }

  void to_json(nlohmann::json &j, const RequiredAttributes &v)
  {
    j["maxHealth"] = v.maxHealth;
    j["appearance"] = v.appearance;
    j["nameTranslationKey"] = v.nameTranslationKey;

    nlohmann::json busyArr = nlohmann::json::array();
    for (const auto &b : v.busyStates)
      busyArr.push_back(b);
    j["busyStates"] = busyArr;

    nlohmann::json motionArr = nlohmann::json::array();
    for (const auto &m : v.motionControllerList)
    {
      if (m == nullptr)
        continue;
      nlohmann::json motionControllerJSON;
      to_json(motionControllerJSON, *m);
      motionArr.push_back(motionControllerJSON);
    }
    j["motionControllerList"] = motionArr;
  }

  void to_json(nlohmann::json &j, const Attributes &v)
  {
    to_json(j, v.requiredAttributes);

    opt_to_json(j, "initialMotionController", v.initialMotionController);
    opt_to_json(j, "displayNames", v.displayNames);
    opt_to_json(j, "opaqueBlockSet", v.opaqueBlockSet);
    opt_to_json(j, "knockbackScale", v.knockbackScale);
    opt_to_json(j, "inventorySize", v.inventorySize);
    opt_to_json(j, "hotbarSize", v.hotbarSize);
    opt_to_json(j, "offhandSlots", v.offhandSlots);
    opt_to_json(j, "hotbarItems", v.hotbarItems);
    opt_to_json(j, "offhandItems", v.offhandItems);
    opt_to_json(j, "possibleInventoryItems", v.possibleInventoryItems);
    opt_to_json(j, "defaultOffhandSlot", v.defaultOffhandSlot);
    opt_to_json(j, "dropList", v.dropList);
    opt_to_json(j, "startState", v.startState);
    opt_to_json(j, "defaultSubState", v.defaultSubState);
    opt_to_json(j, "collisionDistance", v.collisionDistance);
    opt_to_json(j, "combatConfig", v.combatConfig);
    opt_to_json(j, "invulnerable", v.invulnerable);
    opt_to_json(j, "pickupDropOnDeath", v.pickupDropOnDeath);
    opt_to_json(j, "deathInteraction", v.deathInteraction);
    opt_to_json(j, "defaultPlayerAttitude", v.defaultPlayerAttitude);
    opt_to_json(j, "defaultNPCAttitude", v.defaultNPCAttitude);
    opt_to_json(j, "attitudeGroup", v.attitudeGroup);
    opt_to_json(j, "itemAttitudeGroup", v.itemAttitudeGroup);
    opt_to_json(j, "corpseStaysInFlock", v.corpseStaysInFlock);
    opt_to_json(j, "instructions", v.instructions);
    if (v.interactionInstruction.has_value())
      j["interactionInstruction"] = v.interactionInstruction.value();
    if (v.deathInstruction.has_value())
      j["deathInstruction"] = v.deathInstruction.value();
    opt_to_json(j, "stateTransitions", v.stateTransitions);
    opt_to_json(j, "isMemory", v.isMemory);
    opt_to_json(j, "memoriesCategory", v.memoriesCategory);
    opt_to_json(j, "memoriesNameOverride", v.memoriesNameOverride);
    opt_to_json(j, "spawnLockTime", v.spawnLockTime);
  }

